/**
 * formatters.js — Utilitaires de formatage — D2F Webapp
 * Conformité DSI §1.3 : Modularité et Réutilisabilité
 * ─────────────────────────────────────────────────────
 * Centralise toutes les fonctions de formatage pour éviter
 * la duplication de logique dans les composants.
 */

// ── Dates ─────────────────────────────────────────────────────────────────────

/**
 * Formate une date ISO en format lisible fr-FR (ex: "12 janv. 2025")
 * @param {string|Date|null} value
 * @returns {string}
 */
export const formatDate = (value) => {
  if (!value) return "—";
  const d = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(d.getTime())) return "—";
  return d.toLocaleDateString("fr-FR", {
    day: "2-digit",
    month: "short",
    year: "numeric",
  });
};

/**
 * Formate une date ISO avec heure (ex: "12 janv. 2025, 14:30")
 * @param {string|Date|null} value
 * @returns {string}
 */
export const formatDateTime = (value) => {
  if (!value) return "—";
  const d = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(d.getTime())) return "—";
  return d.toLocaleString("fr-FR", {
    day: "2-digit",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
};

/**
 * Formate une date ISO en format court (ex: "12/01/2025")
 * @param {string|Date|null} value
 * @returns {string}
 */
export const formatDateShort = (value) => {
  if (!value) return "—";
  const d = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(d.getTime())) return "—";
  return d.toLocaleDateString("fr-FR");
};

/**
 * Retourne le temps relatif depuis une date (ex: "il y a 3 jours")
 * @param {string|Date|null} value
 * @returns {string}
 */
export const formatRelativeTime = (value) => {
  if (!value) return "—";
  const d = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(d.getTime())) return "—";

  const diffMs = Date.now() - d.getTime();
  const diffSec = Math.floor(diffMs / 1000);
  const diffMin = Math.floor(diffSec / 60);
  const diffH   = Math.floor(diffMin / 60);
  const diffDay = Math.floor(diffH / 24);

  if (diffSec < 60)  return "À l'instant";
  if (diffMin < 60)  return `Il y a ${diffMin} min`;
  if (diffH < 24)    return `Il y a ${diffH}h`;
  if (diffDay < 30)  return `Il y a ${diffDay} jour${diffDay > 1 ? "s" : ""}`;
  return formatDate(d);
};

// ── Texte ─────────────────────────────────────────────────────────────────────

/**
 * Tronque un texte à n caractères et ajoute "…"
 * @param {string|null} text
 * @param {number} n
 * @returns {string}
 */
export const truncate = (text, n = 80) => {
  if (!text) return "";
  const str = String(text);
  return str.length > n ? `${str.slice(0, n)}…` : str;
};

/**
 * Capitalise la première lettre, met le reste en minuscules
 * @param {string|null} str
 * @returns {string}
 */
export const capitalize = (str) => {
  if (!str) return "";
  const s = String(str);
  return s.charAt(0).toUpperCase() + s.slice(1).toLowerCase();
};

/**
 * Met en titre chaque mot (ex: "gestion des compétences" → "Gestion Des Compétences")
 * @param {string|null} str
 * @returns {string}
 */
export const toTitleCase = (str) => {
  if (!str) return "";
  return String(str)
    .toLowerCase()
    .split(" ")
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(" ");
};

/**
 * Normalise une chaîne pour la recherche : minuscules + suppression des accents
 * @param {string|null} str
 * @returns {string}
 */
export const normalizeForSearch = (str) => {
  if (!str) return "";
  return String(str)
    .toLowerCase()
    .normalize("NFD")
    .replaceAll(/[\u0300-\u036f]/g, "");
};

// ── Nombres ───────────────────────────────────────────────────────────────────

/**
 * Formate un nombre avec séparateur de milliers (ex: 1 234 567)
 * @param {number|null} value
 * @returns {string}
 */
export const formatNumber = (value) => {
  if (value === null || value === undefined) return "—";
  return Number(value).toLocaleString("fr-FR");
};

/**
 * Formate un pourcentage (ex: 0.856 → "85,6 %")
 * @param {number|null} value   Valeur entre 0 et 1
 * @param {number}      digits  Nombre de décimales
 * @returns {string}
 */
export const formatPercent = (value, digits = 1) => {
  if (value === null || value === undefined) return "—";
  return `${(Number(value) * 100).toFixed(digits).replaceAll(".", ",")} %`;
};

// ── Codes / Labels ────────────────────────────────────────────────────────────

/**
 * Formate un code en majuscules avec tirets (ex: "inf 01" → "INF-01")
 * @param {string|null} code
 * @returns {string}
 */
export const formatCode = (code) => {
  if (!code) return "";
  return String(code).toUpperCase().replaceAll(/\s+/g, "-");
};

/**
 * Retourne le label d'un NiveauMaitrise (ex: "N3_INTERMEDIAIRE" → "N3 — Intermédiaire")
 * @param {string|null} niveau
 * @returns {string}
 */
export const formatNiveauMaitrise = (niveau) => {
  const labels = {
    N1_DEBUTANT:       "N1 — Débutant",
    N2_ELEMENTAIRE:    "N2 — Élémentaire",
    N3_INTERMEDIAIRE:  "N3 — Intermédiaire",
    N4_AVANCE:         "N4 — Avancé",
    N5_EXPERT:         "N5 — Expert",
  };
  return labels[niveau] ?? niveau ?? "—";
};

/**
 * Retourne le label d'un TypeSavoir (ex: "THEORIQUE" → "Théorique")
 * @param {string|null} type
 * @returns {string}
 */
export const formatTypeSavoir = (type) => {
  const labels = {
    THEORIQUE: "Théorique",
    PRATIQUE:  "Pratique",
  };
  return labels[type] ?? type ?? "—";
};

/**
 * validators.js — Utilitaires de validation — D2F Webapp
 * Conformité DSI §1.3 : Modularité et Réutilisabilité
 *
 * Fournit des règles de validation réutilisables compatibles Ant Design Form
 * ainsi que des fonctions de validation pures utilisables partout.
 */

// =============================================================================
// FONCTIONS DE VALIDATION PURES
// =============================================================================

/**
 * Vérifie qu'une valeur n'est pas vide (null, undefined, chaîne vide ou espaces).
 * @param {*} value
 * @returns {boolean}
 */
export const isNotEmpty = (value) =>
  value !== null && value !== undefined && String(value).trim().length > 0;

/**
 * Vérifie le format d'une adresse email.
 * @param {string} email
 * @returns {boolean}
 */
export const isValidEmail = (email) =>
  /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email ?? "");

/**
 * Vérifie la longueur minimale d'une chaîne.
 * @param {string} value
 * @param {number} min
 * @returns {boolean}
 */
export const minLength = (value, min) =>
  String(value ?? "").trim().length >= min;

/**
 * Vérifie la longueur maximale d'une chaîne.
 * @param {string} value
 * @param {number} max
 * @returns {boolean}
 */
export const maxLength = (value, max) =>
  String(value ?? "").trim().length <= max;

/**
 * Vérifie qu'une valeur est un nombre positif.
 * @param {*} value
 * @returns {boolean}
 */
export const isPositiveNumber = (value) =>
  !Number.isNaN(value) && Number(value) > 0;

/**
 * Vérifie qu'une valeur est un entier positif ou nul.
 * @param {*} value
 * @returns {boolean}
 */
export const isNonNegativeInteger = (value) =>
  Number.isInteger(Number(value)) && Number(value) >= 0;

/**
 * Vérifie qu'un code respecte le format attendu (lettres, chiffres, tirets).
 * Ex : "INF-01", "GC-SC-02"
 * @param {string} code
 * @returns {boolean}
 */
export const isValidCode = (code) =>
  /^[A-Za-z0-9_-]{1,50}$/.test(code ?? "");

// =============================================================================
// RÈGLES ANT DESIGN — utilisables directement dans Form.Item rules={[...]}
// =============================================================================

/**
 * Règle : champ obligatoire.
 * @param {string} [message]
 * @returns {import('antd/es/form').Rule}
 */
export const requiredRule = (message = "Ce champ est obligatoire") => ({
  required: true,
  message,
});

/**
 * Règle : email valide.
 * @param {string} [message]
 * @returns {import('antd/es/form').Rule}
 */
export const emailRule = (message = "Adresse email invalide") => ({
  type: "email",
  message,
});

/**
 * Règle : longueur minimale.
 * @param {number} min
 * @param {string} [message]
 * @returns {import('antd/es/form').Rule}
 */
export const minLengthRule = (min, message) => ({
  min,
  message: message ?? `Minimum ${min} caractère(s) requis`,
});

/**
 * Règle : longueur maximale.
 * @param {number} max
 * @param {string} [message]
 * @returns {import('antd/es/form').Rule}
 */
export const maxLengthRule = (max, message) => ({
  max,
  message: message ?? `Maximum ${max} caractère(s) autorisés`,
});

/**
 * Règle : nombre positif.
 * @param {string} [message]
 * @returns {import('antd/es/form').Rule}
 */
export const positiveNumberRule = (message = "La valeur doit être un nombre positif") => ({
  validator(_, value) {
    if (!value || isPositiveNumber(value)) return Promise.resolve();
    return Promise.reject(new Error(message));
  },
});

/**
 * Règle : format de code valide (lettres, chiffres, tirets, underscores).
 * @param {string} [message]
 * @returns {import('antd/es/form').Rule}
 */
export const codeFormatRule = (message = "Format invalide (lettres, chiffres, tirets uniquement)") => ({
  validator(_, value) {
    if (!value || isValidCode(value)) return Promise.resolve();
    return Promise.reject(new Error(message));
  },
});

/**
 * Règle : valeur comprise entre min et max (inclus).
 * @param {number} min
 * @param {number} max
 * @param {string} [message]
 * @returns {import('antd/es/form').Rule}
 */
export const rangeRule = (min, max, message) => ({
  validator(_, value) {
    const num = Number(value);
    if (!value || (num >= min && num <= max)) return Promise.resolve();
    return Promise.reject(
      new Error(message ?? `La valeur doit être comprise entre ${min} et ${max}`)
    );
  },
});

/**
 * Règle : pas d'espaces en début/fin.
 * @param {string} [message]
 * @returns {import('antd/es/form').Rule}
 */
export const noLeadingTrailingSpacesRule = (
  message = "Pas d'espaces en début ou en fin de chaîne"
) => ({
  validator(_, value) {
    if (!value || value === value.trim()) return Promise.resolve();
    return Promise.reject(new Error(message));
  },
});

/**
 * Règle : confirmation de mot de passe (valeur identique à un autre champ).
 * @param {Function} getFieldValue — fourni par Form instance
 * @param {string} fieldName — nom du champ à comparer
 * @param {string} [message]
 * @returns {import('antd/es/form').Rule}
 */
export const confirmPasswordRule = (
  getFieldValue,
  fieldName = "password",
  message = "Les mots de passe ne correspondent pas"
) => ({
  validator(_, value) {
    if (!value || getFieldValue(fieldName) === value) return Promise.resolve();
    return Promise.reject(new Error(message));
  },
});

// =============================================================================
// COMBINAISONS PRÊTES À L'EMPLOI
// =============================================================================

/**
 * Règles standard pour un champ "nom" (obligatoire, 2–100 chars, pas d'espaces parasites).
 * @param {string} [label="Ce champ"]
 * @returns {import('antd/es/form').Rule[]}
 */
export const nomRules = (label = "Ce champ") => [
  requiredRule(`${label} est obligatoire`),
  minLengthRule(2, `${label} doit contenir au moins 2 caractères`),
  maxLengthRule(100, `${label} ne peut pas dépasser 100 caractères`),
  noLeadingTrailingSpacesRule(),
];

/**
 * Règles standard pour un champ "code" (obligatoire + format alphanumérique).
 * @returns {import('antd/es/form').Rule[]}
 */
export const codeRules = () => [
  requiredRule("Le code est obligatoire"),
  maxLengthRule(50, "Le code ne peut pas dépasser 50 caractères"),
  codeFormatRule(),
];

/**
 * Règles standard pour un champ "description" (optionnel, max 500 chars).
 * @returns {import('antd/es/form').Rule[]}
 */
export const descriptionRules = () => [
  maxLengthRule(500, "La description ne peut pas dépasser 500 caractères"),
];

/**
 * Règles standard pour un champ "email" (obligatoire + format).
 * @returns {import('antd/es/form').Rule[]}
 */
export const emailRules = () => [
  requiredRule("L'adresse email est obligatoire"),
  emailRule(),
];

/**
 * storage.js — Abstraction du localStorage — D2F Webapp
 * =============================================================================
 * Centralise toutes les clés localStorage pour éviter les fautes de frappe
 * dispersées dans le code et faciliter la maintenance.
 *
 * Conformité DSI §1.3 : Modularité et Réutilisabilité
 * Conformité DSI §1.4 : Organisation Structurée du Code (src/utils/)
 * =============================================================================
 */

// ── Clés centralisées ─────────────────────────────────────────────────────────
const KEYS = {
  AUTH_TOKEN: "authToken",
  USER_PROFILE: "userProfile",
  ACTIVE_ROLE: "activeRole",
  PREFERRED_LANG: "preferredLang",
};

// ── Token JWT — DEPRECATED ────────────────────────────────────────────────────
// JWT est maintenant stocké en HttpOnly cookie (withCredentials: true).
// Ces fonctions ne font rien et sont conservées uniquement pour éviter de
// casser d'éventuels imports existants. À supprimer lors du prochain refactor.

/** @deprecated JWT est en HttpOnly cookie. Retourne toujours null. */
export const getToken = (): null => null;

/** @deprecated JWT est positionné par le backend via Set-Cookie. */
export const setToken = (_token: string): void => { /* no-op */ };

/** @deprecated Utilisez AuthService.logout() pour invalider la session. */
export const removeToken = (): void => { /* no-op */ };

/** @deprecated JWT est en HttpOnly cookie, non accessible depuis JS. */
export const hasToken = (): false => false;

// ── Profil utilisateur ────────────────────────────────────────────────────────

/**
 * Récupère le profil utilisateur désérialisé.
 * @returns {object|null}
 */
export const getProfile = () => {
  const raw = localStorage.getItem(KEYS.USER_PROFILE);
  try {
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
};

/**
 * Stocke le profil utilisateur sérialisé.
 * @param {object} profile
 */
export const setProfile = (profile: Record<string, unknown>): void =>
  localStorage.setItem(KEYS.USER_PROFILE, JSON.stringify(profile));

/**
 * Supprime le profil utilisateur.
 */
export const removeProfile = () => localStorage.removeItem(KEYS.USER_PROFILE);

// ── Rôle actif ────────────────────────────────────────────────────────────────

/**
 * Récupère le rôle actif de l'utilisateur.
 * @returns {string|null}
 */
export const getActiveRole = () => localStorage.getItem(KEYS.ACTIVE_ROLE);

/**
 * Stocke le rôle actif.
 * @param {string} role
 */
export const setActiveRole = (role: string): void =>
  localStorage.setItem(KEYS.ACTIVE_ROLE, role);

/**
 * Supprime le rôle actif.
 */
export const removeActiveRole = () => localStorage.removeItem(KEYS.ACTIVE_ROLE);

// ── Langue préférée ───────────────────────────────────────────────────────────

/**
 * Récupère la langue préférée de l'utilisateur.
 * @returns {string} code langue (ex: "fr", "en"), "fr" par défaut
 */
export const getPreferredLang = () =>
  localStorage.getItem(KEYS.PREFERRED_LANG) ?? "fr";

/**
 * Stocke la langue préférée.
 * @param {string} lang
 */
export const setPreferredLang = (lang: string): void =>
  localStorage.setItem(KEYS.PREFERRED_LANG, lang);

// ── Utilitaires globaux ───────────────────────────────────────────────────────

/**
 * Supprime toutes les données de session (logout complet).
 */
export const clearSession = () => {
  localStorage.removeItem(KEYS.USER_PROFILE);
  localStorage.removeItem(KEYS.ACTIVE_ROLE);
};

/**
 * Objet regroupant toutes les méthodes (API objet alternative).
 * Utile pour les injections de dépendances ou les tests.
 */
export const storage = {
  getToken,
  setToken,
  removeToken,
  hasToken,
  getProfile,
  setProfile,
  removeProfile,
  getActiveRole,
  setActiveRole,
  removeActiveRole,
  getPreferredLang,
  setPreferredLang,
  clearSession,
};

export default storage;

/**
 * http.js — Utilitaires HTTP — D2F Webapp
 * Conformité DSI §1.3 : Modularité et Réutilisabilité
 * ─────────────────────────────────────────────────────────────────────────────
 * Centralise les helpers liés aux appels HTTP/Axios :
 *   - Extraction de messages d'erreur depuis les réponses Axios
 *   - Construction des headers Authorization JWT
 *   - Construction des paramètres de pagination standards
 * ─────────────────────────────────────────────────────────────────────────────
 */

/**
 * Extrait le message d'erreur lisible depuis une erreur Axios.
 *
 * Priorité de résolution :
 *   1. response.data.message  (erreur métier Spring Boot)
 *   2. response.data.error    (erreur standard Spring)
 *   3. response.data (si string)
 *   4. error.message          (erreur réseau / JS)
 *   5. fallback fourni en paramètre
 *
 * @param {unknown} error    - L'erreur capturée dans un catch
 * @param {string}  fallback - Message par défaut si rien n'est résolu
 * @returns {string}
 */
export const extractErrorMessage = (
  error: unknown,
  fallback = "Une erreur est survenue. Veuillez réessayer."
) => {
  if (!error) return fallback;

  const data = error?.response?.data;

  if (data) {
    if (typeof data === "string" && data.trim().length > 0) return data.trim();
    if (typeof data.message === "string" && data.message.trim().length > 0)
      return data.message.trim();
    if (typeof data.error === "string" && data.error.trim().length > 0)
      return data.error.trim();
  }

  if (typeof error.message === "string" && error.message.trim().length > 0)
    return error.message.trim();

  return fallback;
};

/**
 * Extrait le code HTTP d'une erreur Axios.
 *
 * @param {unknown} error
 * @returns {number|null}
 */
export const extractStatusCode = (error: unknown): number | null =>
  (error as { response?: { status?: number } })?.response?.status ?? null;

/**
 * Vérifie si l'erreur correspond à un code HTTP 401 (non authentifié).
 *
 * @param {unknown} error
 * @returns {boolean}
 */
export const isUnauthorized = (error: unknown): boolean => extractStatusCode(error) === 401;

/**
 * Vérifie si l'erreur correspond à un code HTTP 403 (interdit).
 *
 * @param {unknown} error
 * @returns {boolean}
 */
export const isForbidden = (error: unknown): boolean => extractStatusCode(error) === 403;

/**
 * Vérifie si l'erreur correspond à un code HTTP 404 (non trouvé).
 *
 * @param {unknown} error
 * @returns {boolean}
 */
export const isNotFound = (error: unknown): boolean => extractStatusCode(error) === 404;

// ─────────────────────────────────────────────────────────────────────────────
// Headers (no-ops — JWT is in HttpOnly cookie, sent automatically)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * @deprecated JWT est en HttpOnly cookie, envoyé automatiquement via withCredentials.
 * Retourne toujours un objet vide. Conservé pour compatibilité des imports existants.
 */
export const authHeader = (): Record<string, string> => ({});

/**
 * @deprecated JWT est en HttpOnly cookie. Retourne uniquement Content-Type.
 * Conservé pour compatibilité des imports existants.
 */
export const jsonAuthHeaders = (): Record<string, string> => ({
  "Content-Type": "application/json",
});

// ─────────────────────────────────────────────────────────────────────────────
// Pagination
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Construit les paramètres de pagination conformes à l'API Spring Boot Pageable.
 *
 * Conformité DSI §2.2 : Pagination obligatoire sur les listes volumineuses.
 * Paramètres standards : page (0-based), size, sort.
 *
 * @param {object} options
 * @param {number} [options.page=0]   - Numéro de page (0-based)
 * @param {number} [options.size=20]  - Nombre d'éléments par page
 * @param {string} [options.sort=""]  - Tri ex: "nom,asc" ou "createdAt,desc"
 * @returns {Record<string, string|number>}
 *
 * @example
 * axios.get("/api/v1/competences", {
 *   params: paginationParams({ page: 0, size: 10, sort: "nom,asc" }),
 *   headers: authHeader(),
 * });
 */
export const paginationParams = ({ page = 0, size = 20, sort = "" } = {}) => ({
  page,
  size,
  ...(sort ? { sort } : {}),
});

/**
 * Extrait les métadonnées de pagination depuis une réponse Spring Boot Page<T>.
 *
 * @param {object} pageResponse - Objet Page<T> retourné par Spring Boot
 * @returns {{
 *   content: Array,
 *   totalElements: number,
 *   totalPages: number,
 *   currentPage: number,
 *   pageSize: number,
 *   isFirst: boolean,
 *   isLast: boolean,
 * }}
 */
export const extractPageData = (pageResponse: unknown): { content: unknown[]; totalElements: number; totalPages: number; currentPage: number; pageSize: number; isFirst: boolean; isLast: boolean } => {
  if (!pageResponse || typeof pageResponse !== "object") {
    return {
      content: [],
      totalElements: 0,
      totalPages: 0,
      currentPage: 0,
      pageSize: 20,
      isFirst: true,
      isLast: true,
    };
  }

  return {
    content: pageResponse.content ?? [],
    totalElements: pageResponse.totalElements ?? 0,
    totalPages: pageResponse.totalPages ?? 0,
    currentPage: pageResponse.number ?? 0,
    pageSize: pageResponse.size ?? 20,
    isFirst: pageResponse.first ?? true,
    isLast: pageResponse.last ?? true,
  };
};

// ─────────────────────────────────────────────────────────────────────────────
// Helpers divers
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Construit une query string à partir d'un objet de paramètres,
 * en ignorant les valeurs null, undefined et chaînes vides.
 *
 * @param {Record<string, unknown>} params
 * @returns {string} - Ex: "page=0&size=20&sort=nom%2Casc"
 */
export const buildQueryString = (params: Record<string, unknown> = {}): string => {
  const entries = Object.entries(params).filter(
    ([, v]) => v !== null && v !== undefined && v !== ""
  );
  return new URLSearchParams(entries).toString();
};
